insert into public.material_catalog (
  category_id,
  subcategory_id,
  name,
  unit,
  package_unit,
  default_minimum_stock,
  short_description,
  search_terms,
  typical_use,
  manufacturer,
  popularity
)
select
  c.id,
  s.id,
  r.name,
  r.unit,
  r.package_unit,
  r.default_minimum_stock,
  r.short_description,
  r.search_terms,
  r.typical_use,
  r.manufacturer,
  r.popularity
from catalog_rows r
join public.material_categories c on c.slug = r.category_slug
left join public.material_subcategories s on s.category_id = c.id and s.slug = r.subcategory_slug
on conflict (name, unit, package_unit) do update set
  category_id = excluded.category_id,
  subcategory_id = excluded.subcategory_id,
  default_minimum_stock = excluded.default_minimum_stock,
  short_description = excluded.short_description,
  search_terms = excluded.search_terms,
  typical_use = excluded.typical_use,
  manufacturer = excluded.manufacturer,
  popularity = excluded.popularity,
  active = true;

insert into public.material_aliases (catalog_item_id, alias)
select mc.id, aliases.alias_value
from public.material_catalog mc
cross join lateral unnest(mc.search_terms) as aliases(alias_value)
where mc.active = true
on conflict (catalog_item_id, alias) do nothing;

