insert into public.material_calculation_rules (
  company_id,
  rule_key,
  roof_type,
  name,
  material_name,
  catalog_item_id,
  unit,
  calculation_method,
  factor,
  spacing_m,
  waste_applies,
  sort_order
)
select
  null,
  r.rule_key,
  r.roof_type,
  r.name,
  r.material_name,
  mc.id,
  r.unit,
  r.calculation_method,
  r.factor,
  r.spacing_m,
  r.waste_applies,
  r.sort_order
from rule_rows r
left join public.material_catalog mc on mc.name = r.material_name
on conflict (rule_key) where company_id is null do update set
  roof_type = excluded.roof_type,
  name = excluded.name,
  material_name = excluded.material_name,
  catalog_item_id = excluded.catalog_item_id,
  unit = excluded.unit,
  calculation_method = excluded.calculation_method,
  factor = excluded.factor,
  spacing_m = excluded.spacing_m,
  waste_applies = excluded.waste_applies,
  sort_order = excluded.sort_order,
  active = true;
